def rob(nums: list[int]) -> int:
    if not nums:
        return 0
    elif len(nums) == 1:
        return nums[0]

    prev, curr = 0, nums[0]
    for i in range(1, len(nums)):
        temp = max(curr, prev + nums[i])
        prev = curr
        curr = temp

    return curr

