def matrixChainOrder(p: list[int]) -> int:
    n = len(p)
    m = [[0 for x in range(n)] for x in range(n)]
    for l in range(2, n):
        for i in range(n-l+1):
            j = i+l-1
            m[i][j] = float('inf')
            for k in range(i, j):
                q = m[i][k] + m[k+1][j] + p[i]*p[k]*p[j]
                if q < m[i][j]:
                    m[i][j] = q
    return m[0][n-1]

