def hasCycle(adj: list[list[int]]) -> bool:
    visited = [False] * len(adj)
    rec_stack = [False] * len(adj)

    def dfs(node):
        if rec_stack[node]:
            return True
        if visited[node]:
            return False
        visited[node] = True
        rec_stack[node] = True
        for neighbor in adj[node]:
            if dfs(neighbor):
                return True
        rec_stack[node] = False
        return False

    for node in range(len(adj)):
        if not visited[node]:
            if dfs(node):
                return True
    return False

