def bfs(adj: list[list[int]], s: int) -> list[int]:
    visited = [False] * len(adj)
    queue = [s]
    result = []

    while queue:
        node = queue.pop(0)
        if not visited[node]:
            visited[node] = True
            result.append(node)
            for neighbor in adj[node]:
                if not visited[neighbor]:
                    queue.append(neighbor)

    return result

