def countSCC(adj):
    n = len(adj)
    visited = [False] * n
    stack = []

    def dfs1(u):
        visited[u] = True
        for v in adj[u]:
            if not visited[v]:
                dfs1(v)
        stack.append(u)

    def dfs2(u, component):
        visited[u] = True
        component.add(u)
        for v in adj[u]:
            if not visited[v]:
                dfs2(v, component)

    scc_count = 0
    while stack:
        u = stack.pop()
        if not visited[u]:
            component = set()
            dfs2(u, component)
            scc_count += 1

    return scc_count

